module q_module (
    input [1:0] s,
    output reg not_e
);

    always @(*) begin
        case (s)
            2'b00: not_e = 0;
            2'b01: not_e = 1;
            2'b10: not_e = 0;
            2'b11: not_e = 1;
            default: not_e = 0; // Default case
        endcase
    end
endmodule
